                                                                           var ifaces = new HashSet<string>(StringComparer.Ordinal);
                                                                           foreach (var h in obj)
                                                                           {
                                                                               if (h != null && !string.IsNullOrEmpty(h.InterfaceName))
                                                                                   ifaces.Add(h.InterfaceName);
                                                                           }

                                                                           var registrations = new List<IDisposable>();

                                                                           foreach (var handler in obj)
                                                                           {
                                                                               if (handler == null || string.IsNullOrEmpty(handler.InterfaceName))
                                                                                   continue;

                                                                               registrations.Add(
                                                                                   connection.RegisterObject(
                                                                                       obj.Path,
                                                                                       handler.InterfaceName,
                                                                                       handler.HandleMethodAsync,
                                                                                       synchronizationContext));
                                                                           }

