                                                                           }

                                                                           if (bi.EnableIntrospectableInterface && !ifaces.Contains(DBusBuiltIns.IntrospectableInterfaceName))
                                                                           {
                                                                               registrations.Add(
                                                                                   connection.RegisterObject(
